from dataclasses import dataclass, field
from typing import Optional

@dataclass
class AssessmentAttempt:
    employee_id: str
    module_id: str
    attempt_number: int
    score_pct: float
    passed: bool
    completed_at: str

@dataclass
class TrainingRecord:
    employee_id: str
    module_id: str
    assigned_at: str
    due_date: str
    attempts: list[AssessmentAttempt] = field(default_factory=list)
    attestation_signed_at: Optional[str] = None

    def is_passed(self) -> bool:
        return any(a.passed for a in self.attempts)

    def is_complete(self) -> bool:
        return self.is_passed() and self.attestation_signed_at is not None

    def is_overdue(self, today: str) -> bool:
        return today > self.due_date and not self.is_complete()

    def failed_attempts(self) -> int:
        return sum(1 for a in self.attempts if not a.passed)

    def requires_manager_notification(self) -> bool:
        return self.failed_attempts() >= 2 and not self.is_passed()

    def status(self) -> str:
        if self.is_complete():
            return "complete"
        if not self.attempts:
            return "not_started"
        if self.is_passed():
            return "passed_awaiting_attestation"
        return "in_progress"
